```typescript
class EnemySpawner {
    private _container: cc.Node;
    private _enemies: ccs.Armature[] = [];
    private _exportJson: string;
    private _armatureName: string;
    private static readonly MAX_ENEMIES = 10;

    constructor(container: cc.Node, armatureName: string, exportJson: string) {
        this._container = container;
        this._armatureName = armatureName;
        this._exportJson = exportJson;
        ccs.armatureDataManager.addArmatureFileInfo(this._exportJson);
    }

    spawn(position: cc.Point): ccs.Armature | null {
        if (this._enemies.length >= EnemySpawner.MAX_ENEMIES) return null;

        const enemy = ccs.Armature.create(this._armatureName);
        enemy.setPosition(position);
        this._container.addChild(enemy);

        enemy.animation.play('spawn', -1, 0);
        enemy.animation.setMovementEventCallFunc((arm, type, id) => {
            if (type === ccs.MovementEventType.COMPLETE && id === 'spawn') {
                arm.animation.play('idle', 5, -1);
            }
        });

        this._enemies.push(enemy);
        return enemy;
    }

    despawn(enemy: ccs.Armature): void {
        const idx = this._enemies.indexOf(enemy);
        if (idx === -1) return;

        enemy.animation.play('death', -1, 0);
        enemy.animation.setMovementEventCallFunc((arm, type, id) => {
            if (type === ccs.MovementEventType.COMPLETE && id === 'death') {
                arm.removeFromParent(true);
            }
        });
        this._enemies.splice(idx, 1);
    }

    despawnAll(): void {
        for (const enemy of this._enemies.slice()) {
            enemy.removeFromParent(true);
        }
        this._enemies = [];
    }

    getCount(): number {
        return this._enemies.length;
    }
}

// Usage:
const spawner = new EnemySpawner(this, 'goblin', 'res/goblin/goblin.ExportJson');
spawner.spawn(cc.p(100, 100));
spawner.spawn(cc.p(300, 100));
```

