```typescript
class AnimStateMachine {
    private _armature: ccs.Armature;
    private _currentState: string = '';
    private _transitions: Map<string, string[]> = new Map();
    private _blendFrames: number;

    constructor(armature: ccs.Armature, initialState: string, blendFrames: number = 5) {
        this._armature = armature;
        this._blendFrames = blendFrames;
        this._currentState = initialState;
        this._armature.animation.play(initialState, -1, -1);
    }

    addTransition(from: string, to: string): void {
        if (!this._transitions.has(from)) {
            this._transitions.set(from, []);
        }
        const targets = this._transitions.get(from)!;
        if (targets.indexOf(to) === -1) {
            targets.push(to);
        }
    }

    canTransition(to: string): boolean {
        const allowed = this._transitions.get(this._currentState);
        if (!allowed) return false;
        return allowed.indexOf(to) !== -1;
    }

    transitionTo(state: string, loop: number = -1): boolean {
        if (!this.canTransition(state)) return false;
        this._currentState = state;
        this._armature.animation.play(state, this._blendFrames, loop);
        return true;
    }

    getCurrentState(): string {
        return this._currentState;
    }

    forceState(state: string, loop: number = -1): void {
        this._currentState = state;
        this._armature.animation.play(state, -1, loop);
    }
}

// Usage:
const arm = ccs.Armature.create('hero');
const sm = new AnimStateMachine(arm, 'idle');

sm.addTransition('idle', 'walk');
sm.addTransition('idle', 'attack');
sm.addTransition('walk', 'idle');
sm.addTransition('walk', 'run');
sm.addTransition('run', 'walk');
sm.addTransition('attack', 'idle');

sm.transitionTo('walk');    // true, idle -> walk
sm.transitionTo('attack');  // false, walk -> attack not defined
sm.transitionTo('run');     // true, walk -> run
```

