class TimelineController {
    private _timeline: ccs.ActionTimeline;
    private _node: cc.Node;
    private _isPlaying: boolean = false;

    constructor(node: cc.Node) {
        this._node = node;
    }

    load(csbFile: string): void {
        this._timeline = ccs.actionManager.loadAnimationActionWithFile(csbFile);
        this._node.runAction(this._timeline);
        this._timeline.gotoFrameAndPause(0);
        this._isPlaying = false;
    }

    play(loop: boolean = false): void {
        if (!this._timeline) return;
        const frame = this._timeline.getCurrentFrame();
        this._timeline.gotoFrameAndPlay(frame, loop);
        this._isPlaying = true;
    }

    playFromStart(loop: boolean = false): void {
        if (!this._timeline) return;
        this._timeline.gotoFrameAndPlay(0, loop);
        this._isPlaying = true;
    }

    pause(): void {
        if (!this._timeline) return;
        const frame = this._timeline.getCurrentFrame();
        this._timeline.gotoFrameAndPause(frame);
        this._isPlaying = false;
    }

    seek(frame: number): void {
        if (!this._timeline) return;
        this._timeline.setCurrentFrame(frame);
        if (!this._isPlaying) {
            this._timeline.gotoFrameAndPause(frame);
        }
    }

    getProgress(): number {
        if (!this._timeline) return 0;
        const start = this._timeline.getStartFrame();
        const end = this._timeline.getEndFrame();
        const cur = this._timeline.getCurrentFrame();
        const range = end - start;
        if (range <= 0) return 0;
        return (cur - start) / range;
    }

    setSpeed(speed: number): void {
        if (!this._timeline) return;
        this._timeline.setTimeSpeed(speed);
    }

    isPlaying(): boolean {
        return this._isPlaying;
    }
}

// Usage:
const ctrl = new TimelineController(dialogNode);
ctrl.load('res/ui/dialog_anim.csb');
ctrl.playFromStart(false);
ctrl.setSpeed(1.5);
```

instruction:
Find and fix the bug in this armature animation code:

```typescript
const armature = ccs.Armature.create('hero');
armature.setPosition(240, 160);
this.addChild(armature);
armature.animation.play('run', -1, 1);
armature.animation.setSpeedScale(1.5);
```

output:
The code will crash because `addArmatureFileInfo` was never called before creating the armature. The armature data must be loaded first.

Fixed code:
```typescript
// Must load data before creating armature
ccs.armatureDataManager.addArmatureFileInfo('res/hero/hero.ExportJson');

const armature = ccs.Armature.create('hero');
armature.setPosition(240, 160);
this.addChild(armature);
armature.animation.play('run', -1, 1);
armature.animation.setSpeedScale(1.5);
```

Always call `ccs.armatureDataManager.addArmatureFileInfo(path)` before `ccs.Armature.create(name)`. Typically this is done during scene loading or initialization.

instruction:
Find and fix the bug in this code that tries to chain animations:

```typescript
ccs.armatureDataManager.addArmatureFileInfo('res/hero/hero.ExportJson');
const armature = ccs.Armature.create('hero');
this.addChild(armature);

armature.animation.play('attack', -1, 0);
armature.animation.play('idle', 5, -1);
```

output:
The bug is that both `play` calls execute immediately. The second `play('idle')` immediately overrides the first `play('attack')`, so the attack animation never actually plays.

To chain animations, use `setMovementEventCallFunc` to wait for the first animation to complete:

Fixed code:
```typescript
ccs.armatureDataManager.addArmatureFileInfo('res/hero/hero.ExportJson');
const armature = ccs.Armature.create('hero');
this.addChild(armature);

// Listen for completion, then transition to idle
armature.animation.setMovementEventCallFunc((arm, type, id) => {
    if (type === ccs.MovementEventType.COMPLETE && id === 'attack') {
        arm.animation.play('idle', 5, -1);
    }
});

armature.animation.play('attack', -1, 0);
```

Alternatively, use `playWithNames` to sequence them:
```typescript
armature.animation.playWithNames(['attack', 'idle'], 5, false);
```

instruction:
Find and fix the bug in this code:

```typescript
ccs.armatureDataManager.addArmatureFileInfo('res/hero/hero.ExportJson');
const armature = ccs.Armature.create('hero');
this.addChild(armature);

armature.getAnimation().play('idle', -1, -1);
armature.getAnimation().setSpeedScale(2.0);
```

output:
This code actually works correctly. Both `armature.animation` (property) and `armature.getAnimation()` (method) return the same `ccs.ArmatureAnimation` instance.

However, there is a style concern: mixing `getAnimation()` calls when you could store a reference. If the code were using `armature.animation` property in some places and `getAnimation()` in others, it would be inconsistent.

Recommended cleaner version:
```typescript
ccs.armatureDataManager.addArmatureFileInfo('res/hero/hero.ExportJson');
const armature = ccs.Armature.create('hero');
this.addChild(armature);

const anim = armature.animation;
anim.play('idle', -1, -1);
anim.setSpeedScale(2.0);
```

Storing the animation reference in a local variable is cleaner and avoids repeated property/method access.

instruction:
Fix the bug in this code that tries to detect which bone was tapped:

```typescript
cc.eventManager.addListener({
    event: cc.EventListener.TOUCH_ONE_BY_ONE,
    onTouchBegan: (touch: cc.Touch): boolean => {
        const loc = touch.getLocation();
        const bone = armature.getBone(loc.x, loc.y);
