```typescript
class BoneDebugView extends cc.Layer {
    private _armature: ccs.Armature;
    private _debugDraw: cc.DrawNode;
    private _boneNames: string[];

    constructor(armatureName: string, exportJson: string, boneNames: string[]) {
        super();
        ccs.armatureDataManager.addArmatureFileInfo(exportJson);
        this._armature = ccs.Armature.create(armatureName);
        this._armature.setPosition(240, 160);
        this.addChild(this._armature);
        this._armature.animation.play('idle', -1, -1);

        this._boneNames = boneNames;
        this._debugDraw = new cc.DrawNode();
        this.addChild(this._debugDraw, 100);
        this.scheduleUpdate();
    }

    update(dt: number): void {
        this._debugDraw.clear();

        for (const name of this._boneNames) {
            const bone = this._armature.getBone(name);
            if (!bone) continue;

            const worldPos = bone.getWorldPosition();

            // Draw bone joint
            this._debugDraw.drawDot(worldPos, 4, cc.color(255, 0, 0, 255));

            // Draw bone name (using a dot + offset for identification)
            this._debugDraw.drawDot(
                cc.p(worldPos.x + 8, worldPos.y + 8),
                2, cc.color(255, 255, 0, 200)
            );
        }

        // Draw connections between adjacent bones
        for (let i = 0; i < this._boneNames.length - 1; i++) {
            const b1 = this._armature.getBone(this._boneNames[i]);
            const b2 = this._armature.getBone(this._boneNames[i + 1]);
            if (!b1 || !b2) continue;
            this._debugDraw.drawSegment(
                b1.getWorldPosition(),
                b2.getWorldPosition(),
                1, cc.color(0, 255, 0, 150)
            );
        }
    }
}

// Usage:
const debug = new BoneDebugView(
    'hero', 'res/hero/hero.ExportJson',
    ['head', 'neck', 'body', 'hip', 'leg_l', 'foot_l']
);
this.addChild(debug);
```

```typescript
class EquippedCharacter extends cc.Node {
    private _armature: ccs.Armature;
    private _equipment: Map<string, cc.Sprite> = new Map();

    constructor(armatureName: string, exportJson: string) {
        super();
        ccs.armatureDataManager.addArmatureFileInfo(exportJson);
        this._armature = ccs.Armature.create(armatureName);
        this.addChild(this._armature);
        this._armature.animation.play('idle', -1, -1);
        this.scheduleUpdate();
    }

    equip(slotBone: string, spriteName: string): void {
        this.unequip(slotBone);
        const bone = this._armature.getBone(slotBone);
        if (!bone) return;

        const itemSprite = new cc.Sprite(
            cc.spriteFrameCache.getSpriteFrame(spriteName)
        );
        this.addChild(itemSprite, 10);
        this._equipment.set(slotBone, itemSprite);
    }

    unequip(slotBone: string): void {
        const existing = this._equipment.get(slotBone);
        if (existing) {
            existing.removeFromParent(true);
            this._equipment.delete(slotBone);
        }
    }

    update(dt: number): void {
        // Update equipment positions to follow bones
        this._equipment.forEach((sprite, boneName) => {
            const bone = this._armature.getBone(boneName);
            if (!bone) return;
            const worldPos = bone.getWorldPosition();
            sprite.setPosition(worldPos);
        });
    }

    playAnimation(name: string, loop: boolean): void {
        const loopVal = loop ? -1 : 0;
        this._armature.animation.play(name, 5, loopVal);
    }
}

// Usage:
cc.spriteFrameCache.addSpriteFrames('res/items.plist', 'res/items.png');
const character = new EquippedCharacter('hero', 'res/hero/hero.ExportJson');
character.setPosition(240, 160);
this.addChild(character);

character.equip('hand_r', 'sword_01.png');
character.equip('head', 'helmet_01.png');
character.playAnimation('walk', true);
```

