class AnimPreviewScene extends cc.Scene {
    private _armature: ccs.Armature;
    private _label: cc.LabelTTF;
    private _animIndex: number = 0;
    private _animCount: number = 0;

    onEnter(): void {
        super.onEnter();

        ccs.armatureDataManager.addArmatureFileInfo('res/hero/hero.ExportJson');
        this._armature = ccs.Armature.create('hero');
        this._armature.setPosition(240, 180);
        this.addChild(this._armature);

        this._animCount = this._armature.animation.getMovementCount();

        this._label = new cc.LabelTTF('', 'Arial', 20);
        this._label.setPosition(240, 30);
        this.addChild(this._label);

        // Play first animation
        this.playCurrentAnim();

        // Cycle on completion
        this._armature.animation.setMovementEventCallFunc((arm, type, id) => {
            if (type === ccs.MovementEventType.COMPLETE ||
                type === ccs.MovementEventType.LOOP_COMPLETE) {
                this.scheduleOnce(() => this.nextAnim(), 1.0);
            }
        });

        // Tap to skip
        cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            onTouchBegan: (): boolean => {
                this.nextAnim();
                return true;
            }
        }, this);
    }

    private nextAnim(): void {
        this._animIndex = (this._animIndex + 1) % this._animCount;
        this.playCurrentAnim();
    }

    private playCurrentAnim(): void {
        this._armature.animation.playWithIndex(this._animIndex, 5, 0);
        const name = this._armature.animation.getCurrentMovementID();
        this._label.setString(this._animIndex + '/' + this._animCount + ': ' + name);
    }
}
```

`drawContour()` is a built-in debug method on `ccs.Armature` that draws the outline/contour of all bones:

```typescript
ccs.armatureDataManager.addArmatureFileInfo('res/hero/hero.ExportJson');
const armature = ccs.Armature.create('hero');
