output:
```typescript
class ArmaturePool {
    private _pool: ccs.Armature[] = [];
    private _armatureName: string;
    private _active: Set<ccs.Armature> = new Set();

    constructor(armatureName: string, exportJson: string) {
        this._armatureName = armatureName;
        ccs.armatureDataManager.addArmatureFileInfo(exportJson);
    }

    preload(count: number): void {
        for (let i = 0; i < count; i++) {
            const arm = ccs.Armature.create(this._armatureName);
            arm.setVisible(false);
            this._pool.push(arm);
        }
    }

    get(): ccs.Armature {
        let arm: ccs.Armature;
        if (this._pool.length > 0) {
            arm = this._pool.pop()!;
        } else {
            arm = ccs.Armature.create(this._armatureName);
        }
        arm.setVisible(true);
        arm.animation.stop();
        arm.animation.setSpeedScale(1.0);
        this._active.add(arm);
        return arm;
    }

    release(arm: ccs.Armature): void {
        if (!this._active.has(arm)) return;
        this._active.delete(arm);
        arm.animation.stop();
        arm.setVisible(false);
        arm.removeFromParent(false);
        this._pool.push(arm);
    }

    releaseAll(): void {
        for (const arm of this._active) {
            arm.animation.stop();
            arm.setVisible(false);
            arm.removeFromParent(false);
            this._pool.push(arm);
        }
        this._active.clear();
    }

    getActiveCount(): number {
        return this._active.size;
    }

    getPoolSize(): number {
        return this._pool.length;
    }
}

// Usage:
const pool = new ArmaturePool('bullet_fx', 'res/fx/bullet.ExportJson');
pool.preload(20);

// Spawn
const fx = pool.get();
fx.setPosition(100, 200);
this.addChild(fx);
fx.animation.play('explode', -1, 0);
fx.animation.setMovementEventCallFunc((arm, type) => {
    if (type === ccs.MovementEventType.COMPLETE) {
        pool.release(arm);
    }
});
```

`ccs.Armature.getBoundingBox()` and a regular `cc.Node.getBoundingBox()` differ in how they compute the rectangle:

**cc.Node.getBoundingBox()**
- Based on the node's `contentSize`, `position`, `anchor`, `scale`, and `rotation`
- Returns a fixed-size rect that doesn't change with animation
- Cheap to compute

**ccs.Armature.getBoundingBox()**
- Recalculates from all bone positions on every call
- Returns a rect that encompasses all visible bones in their current animation pose
- Changes shape as the animation plays (e.g., wider during an attack swing)
- More expensive to compute

```typescript
const armature = ccs.Armature.create('hero');
armature.animation.play('idle', -1, -1);

// This rect changes based on current animation frame
const idleBox: cc.Rect = armature.getBoundingBox();

armature.animation.play('attack', -1, 0);
// After switching to attack, the bounding box may be wider
// because the arm extends outward
const attackBox: cc.Rect = armature.getBoundingBox();
```

Because of the per-call recalculation cost, avoid calling `getBoundingBox()` every frame on many armatures. Cache the result or use it only for broad-phase collision checks.

Use the pause() and resume() methods on ccs.ArmatureAnimation:

```typescript
ccs.armatureDataManager.addArmatureFileInfo('res/hero/hero.ExportJson');
const armature = ccs.Armature.create('hero');
armature.setPosition(240, 160);
this.addChild(armature);
armature.animation.play('run', -1, -1);

// Pause
armature.animation.pause();

// Resume
armature.animation.resume();

// Stop completely (resets)
armature.animation.stop();
```

pause() freezes at the current frame. resume() continues from where paused. stop() halts and resets.

Use playWithIndex to play an animation by its numeric index:

```typescript
ccs.armatureDataManager.addArmatureFileInfo('res/hero/hero.ExportJson');
const armature = ccs.Armature.create('hero');
this.addChild(armature);

// Play first animation (index 0)
armature.animation.playWithIndex(0, -1, -1);

// Play third animation once with 5-frame blend
armature.animation.playWithIndex(2, 5, 0);
```

Signature: `playWithIndex(index: number, durationTo?: number, loop?: number): void`

Use getMovementCount() to know how many animations exist:
```typescript
const total = armature.getMovementCount();
```

