```typescript
class FlippableArmature {
    private _armature: ccs.Armature;
    private _facingRight: boolean = true;

    constructor(name: string, exportJson: string, parent: cc.Node) {
        ccs.armatureDataManager.addArmatureFileInfo(exportJson);
        this._armature = ccs.Armature.create(name);
        parent.addChild(this._armature);
    }

    setFacing(right: boolean): void {
        if (this._facingRight === right) return;
        this._facingRight = right;
        this._armature.setScaleX(right ? 1 : -1);
    }

    isFacingRight(): boolean {
        return this._facingRight;
    }

    getWorldBonePos(boneName: string): cc.Point {
        const bone = this._armature.getBone(boneName);
        if (!bone) return this._armature.getPosition();
        return bone.getWorldPosition();
    }

    getArmature(): ccs.Armature {
        return this._armature;
    }
}

// Usage:
const hero = new FlippableArmature('hero', 'res/hero/hero.ExportJson', this);
hero.getArmature().setPosition(240, 160);
hero.getArmature().animation.play('walk', -1, -1);
hero.setFacing(false);
```

